#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int invalid = 0, weak = 0;
        for (int i = 0; i < N; i++) {
            char status[10], result[M + 1];
            scanf("%s %s", status, result);
            if (strcmp(status, "correct") == 0) {
                for (int j = 0; j < M; j++) {
                    if (result[j] == '0') {
                        invalid = 1;
                        break;
                    }
                }
            } else {
                int allPassed = 1;
                for (int j = 0; j < M; j++) {
                    if (result[j] == '0') {
                        allPassed = 0;
                        break;
                    }
                }
                if (allPassed) {
                    weak = 1;
                }
            }
        }
        if (invalid) {
            printf("INVALID\n");
        } else if (weak) {
            printf("WEAK\n");
        } else {
            printf("FINE\n");
        }
    }
    return 0;
}

