import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt(), M = sc.nextInt();
            int invalid = 0, weak = 0;
            for (int i = 0; i < N; i++) {
                String status = sc.next(), result = sc.next();
                if (status.equals("correct")) {
                    for (int j = 0; j < M; j++) {
                        if (result.charAt(j) == '0') {
                            invalid = 1;
                            break;
                        }
                    }
                } else {
                    int allPassed = 1;
                    for (int j = 0; j < M; j++) {
                        if (result.charAt(j) == '0') {
                            allPassed = 0;
                            break;
                        }
                    }
                    if (allPassed) {
                        weak = 1;
                    }
                }
            }
            if (invalid > 0) {
                System.out.println("INVALID");
            } else if (weak > 0) {
                System.out.println("WEAK");
            } else {
                System.out.println("FINE");
            }
        }
    }
}

